4	import { parseLogFile, formatSize } from './parser.js';
5	import {
6	  renderEntryList,
7	  renderDetailHeader,
8	  renderMessagesTab,
9	  renderSystemTab,
10	  renderToolsTab,
11	  renderRequestTab,
12	  renderResponseTab,
13	  modelLabel,
14	} from './renderer.js';
15	
16	// ===== State =====
17	let state = {
18	  entries: [],
19	  filteredEntries: [],
20	  selectedIndex: -1,
21	  activeTab: 'messages',
22	  fileName: '',
23	  fileSize: 0,
24	  truncated: false,
25	};
26	
27	// ===== DOM References =====
28	const $ = (id) => document.getElementById(id);
29	
30	const dropZone = $('dropZone');
31	const dropZoneContainer = $('dropZoneContainer');
32	const fileInput = $('fileInput');
33	const fileInfo = $('fileInfo');
34	const fileName = $('fileName');
35	const fileSize = $('fileSize');
36	const entryCount = $('entryCount');
37	const truncatedBadge = $('truncatedBadge');
38	const closeFileBtn = $('closeFile');
39	const mainContent = $('mainContent');
40	const entryList = $('entryList');
41	const modelFilter = $('modelFilter');
42	const searchInput = $('searchInput');
43	const filteredCount = $('filteredCount');
44	const detailEmpty = $('detailEmpty');
45	const detailView = $('detailView');
46	const detailHeader = $('detailHeader');
47	const tabContent = $('tabContent');
48	const tabs = $('tabs');
49	const themeToggle = $('themeToggle');
50	const systemCount = $('systemCount');
51	const toolsCount = $('toolsCount');
52	
53	// ===== Theme =====
54	function initTheme() {
55	  const saved = localStorage.getItem('logs-reviewer-theme');
56	  if (saved) {
57	    document.documentElement.dataset.theme = saved;
58	  }
59	  updateThemeIcon();
60	}
61	
62	function toggleTheme() {
63	  const current = document.documentElement.dataset.theme;
64	  const next = current === 'dark' ? 'light' : 'dark';
65	  document.documentElement.dataset.theme = next;
66	  localStorage.setItem('logs-reviewer-theme', next);
67	  updateThemeIcon();
68	}
69	
70	function updateThemeIcon() {
71	  const isDark = document.documentElement.dataset.theme === 'dark';
72	  themeToggle.textContent = isDark ? '\u2600' : '\u263E';
73	}
74	
75	// ===== File Loading =====
76	function handleFiles(files) {
77	  if (!files || files.length === 0) return;
78	
79	  const file = files[0]; // Handle first file
80	  const reader = new FileReader();
81	
82	  reader.onload = (e) => {
83	    try {
84	      const result = parseLogFile(e.target.result);
85	      loadEntries(result.entries, file.name, file.size, result.truncated);
86	    } catch (err) {
87	      alert(`Error parsing file: ${err.message}`);
88	    }
89	  };
90	
91	  reader.onerror = () => {
92	    alert('Error reading file.');
93	  };
94	
95	  reader.readAsText(file);
96	}
97	
98	function loadEntries(entries, name, size, truncated) {
99	  state.entries = entries;
100	  state.fileName = name;
101	  state.fileSize = size;
102	  state.truncated = truncated;
103	  state.selectedIndex = -1;
104	  state.activeTab = 'messages';
105	
106	  // Show file info
107	  fileName.textContent = name;
108	  fileSize.textContent = formatSize(size);
109	  entryCount.textContent = `${entries.length} entries`;
110	  truncatedBadge.classList.toggle('hidden', !truncated);
111	  fileInfo.classList.remove('hidden');
112	
113	  // Compact drop zone
114	  dropZone.classList.add('compact');
115	
116	  // Populate model filter
117	  const models = [...new Set(entries.map(e => e.anthropicRequest?.model || 'unknown'))];
118	  modelFilter.innerHTML = '<option value="">All models</option>';
119	  for (const model of models) {
120	    const opt = document.createElement('option');
121	    opt.value = model;
122	    opt.textContent = model;
123	    modelFilter.appendChild(opt);
124	  }
125	
126	  // Show main content
127	  mainContent.classList.remove('hidden');
128	
129	  // Apply filters and render
130	  applyFilters();
131	
132	  // Auto-select first entry
133	  if (entries.length > 0) {
134	    selectEntry(0);
135	  }
136	}
137	
138	function closeFile() {
139	  state = {
140	    entries: [],
141	    filteredEntries: [],
142	    selectedIndex: -1,
143	    activeTab: 'messages',
144	    fileName: '',
145	    fileSize: 0,
146	    truncated: false,
147	  };
148	
149	  fileInfo.classList.add('hidden');
150	  mainContent.classList.add('hidden');
151	  detailEmpty.classList.remove('hidden');
152	  detailView.classList.add('hidden');
153	  dropZone.classList.remove('compact');
154	  entryList.innerHTML = '';
155	  tabContent.innerHTML = '';
156	  searchInput.value = '';
157	  modelFilter.innerHTML = '<option value="">All models</option>';
158	}
159	
160	// ===== Filtering =====
161	function applyFilters() {
162	  const modelVal = modelFilter.value;
163	  const searchVal = searchInput.value.toLowerCase().trim();
164	
165	  state.filteredEntries = state.entries.filter((entry, i) => {
166	    // Model filter
167	    if (modelVal && (entry.anthropicRequest?.model || 'unknown') !== modelVal) {
168	      return false;
169	    }
170	
171	    // Text search
172	    if (searchVal) {
173	      const messages = entry.anthropicRequest?.messages || [];
174	      const found = messages.some(msg => {
175	        const content = typeof msg.content === 'string'
176	          ? msg.content
177	          : JSON.stringify(msg.content);
178	        return content.toLowerCase().includes(searchVal);
179	      });
180	      if (!found) {
181	        // Also search system prompts
182	        const system = entry.anthropicRequest?.system || [];
183	        const sysFound = system.some(s =>
184	          (s.text || JSON.stringify(s)).toLowerCase().includes(searchVal)
185	        );
186	        if (!sysFound) return false;
187	      }
188	    }
189	
190	    return true;
191	  });
192	
193	  filteredCount.textContent = `${state.filteredEntries.length}/${state.entries.length}`;
194	
195	  renderEntryList(state.filteredEntries, entryList, (filteredIndex) => {
196	    // Map filtered index back to original index
197	    const entry = state.filteredEntries[filteredIndex];
198	    const originalIndex = state.entries.indexOf(entry);
199	    selectEntry(originalIndex);
200	  });
201	
202	  // Highlight active entry in the list
203	  updateActiveEntryInList();
204	}
205	
206	function updateActiveEntryInList() {
207	  const items = entryList.querySelectorAll('.entry-item');
208	  items.forEach((item) => {
209	    const entry = state.filteredEntries[parseInt(item.dataset.index)];
210	    const originalIndex = state.entries.indexOf(entry);
211	    item.classList.toggle('active', originalIndex === state.selectedIndex);
212	  });
213	}
214	
215	// ===== Entry Selection =====
216	function selectEntry(index) {
217	  if (index < 0 || index >= state.entries.length) return;
218	
219	  state.selectedIndex = index;
220	  const entry = state.entries[index];
221	
222	  // Show detail view
223	  detailEmpty.classList.add('hidden');
224	  detailView.classList.remove('hidden');
225	
226	  // Render header
227	  renderDetailHeader(entry, detailHeader);
228	
229	  // Update tab counts
230	  systemCount.textContent = `(${entry.anthropicRequest?.system?.length || 0})`;
231	  toolsCount.textContent = `(${entry.anthropicRequest?.tools?.length || 0})`;
232	
233	  // Render active tab
234	  renderActiveTab();
235	
236	  // Update active entry in sidebar
237	  updateActiveEntryInList();
238	}
239	
240	// ===== Tab Rendering =====
241	function renderActiveTab() {
242	  const entry = state.entries[state.selectedIndex];
243	  if (!entry) return;
244	
245	  tabContent.innerHTML = '';
246	
247	  switch (state.activeTab) {
248	    case 'messages':
249	      tabContent.appendChild(renderMessagesTab(entry));
250	      break;
251	    case 'system':
252	      tabContent.appendChild(renderSystemTab(entry));
253	      break;
254	    case 'tools':
255	      tabContent.appendChild(renderToolsTab(entry));
256	      break;
257	    case 'request':
258	      tabContent.appendChild(renderRequestTab(entry));
259	      break;
260	    case 'response':
261	      tabContent.appendChild(renderResponseTab(entry));
262	      break;
263	  }
264	}
265	
266	function setActiveTab(tabName) {
267	  state.activeTab = tabName;
268	
269	  // Update tab buttons
270	  tabs.querySelectorAll('.tab').forEach(tab => {
271	    tab.classList.toggle('active', tab.dataset.tab === tabName);
272	  });
273	
274	  renderActiveTab();
275	}
276	
277	// ===== Drag & Drop =====
278	function initDragDrop() {
279	  // Prevent default for drag events on the document (prevents browser file open)
280	  ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(event => {
281	    document.addEventListener(event, (e) => {
282	      e.preventDefault();
283	    });
284	  });
285	
286	  // Visual feedback on drop zone
287	  dropZone.addEventListener('dragenter', () => dropZone.classList.add('drag-over'));
288	  dropZone.addEventListener('dragover', () => dropZone.classList.add('drag-over'));
289	  dropZone.addEventListener('dragleave', () => dropZone.classList.remove('drag-over'));
290	
291	  // Also allow dropping anywhere on the page
292	  document.addEventListener('dragenter', () => dropZone.classList.add('drag-over'));
293	  document.addEventListener('dragleave', (e) => {
294	    if (e.relatedTarget === null) {
295	      dropZone.classList.remove('drag-over');
296	    }
297	  });
298	
299	  // Handle drop anywhere on the document (single handler to avoid double processing)
300	  document.addEventListener('drop', (e) => {
301	    dropZone.classList.remove('drag-over');
302	    if (e.dataTransfer.files.length > 0) {
303	      handleFiles(e.dataTransfer.files);
304	    }
305	  });
306	
307	  // Click to browse
308	  dropZone.addEventListener('click', () => fileInput.click());
309	  fileInput.addEventListener('change', () => {
310	    handleFiles(fileInput.files);
311	    fileInput.value = ''; // Reset so same file can be re-selected
312	  });
313	}
314	
315	// ===== Event Listeners =====
316	function initEventListeners() {
317	  // Theme toggle
318	  themeToggle.addEventListener('click', toggleTheme);
319	
320	  // Close file
321	  closeFileBtn.addEventListener('click', closeFile);
322	
323	  // Tab switching
324	  tabs.addEventListener('click', (e) => {
325	    const tab = e.target.closest('.tab');
326	    if (tab && tab.dataset.tab) {
327	      setActiveTab(tab.dataset.tab);
328	    }
329	  });
330	
331	  // Model filter
332	  modelFilter.addEventListener('change', applyFilters);
333	
334	  // Search with debounce
335	  let searchTimeout;
336	  searchInput.addEventListener('input', () => {
337	    clearTimeout(searchTimeout);
338	    searchTimeout = setTimeout(applyFilters, 300);
339	  });
340	
341	  // Keyboard navigation (works with filtered list)
342	  document.addEventListener('keydown', (e) => {
343	    if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT') return;
344	    if (state.filteredEntries.length === 0) return;
345	
346	    // Find current position in filtered list
347	    const currentEntry = state.entries[state.selectedIndex];
348	    const filteredIdx = state.filteredEntries.indexOf(currentEntry);
349	
350	    if (e.key === 'ArrowUp') {
351	      const prevIdx = filteredIdx > 0 ? filteredIdx - 1 : 0;
352	      const originalIndex = state.entries.indexOf(state.filteredEntries[prevIdx]);
353	      if (originalIndex >= 0) selectEntry(originalIndex);
354	    } else if (e.key === 'ArrowDown') {
355	      const nextIdx = filteredIdx < state.filteredEntries.length - 1 ? filteredIdx + 1 : filteredIdx;
356	      const originalIndex = state.entries.indexOf(state.filteredEntries[nextIdx]);
357	      if (originalIndex >= 0) selectEntry(originalIndex);
358	    }
359	  });
360	}
361	
362	// ===== Initialize =====
363	function init() {
364	  initTheme();
365	  initDragDrop();
366	  initEventListeners();
367	}
368	
369	document.addEventListener('DOMContentLoaded', init);
