6	/**
7	 * Get a short model label from full model name.
8	 */
9	export function modelLabel(model) {
10	  if (!model) return 'unknown';
11	  if (model.includes('haiku')) return 'haiku';
12	  if (model.includes('opus')) return 'opus';
13	  if (model.includes('sonnet')) return 'sonnet';
14	  return model.split('-').pop() || model;
15	}
16	
17	/**
18	 * Get model badge CSS class.
19	 */
20	function modelBadgeClass(model) {
21	  if (!model) return '';
22	  if (model.includes('haiku')) return 'haiku';
23	  if (model.includes('opus')) return 'opus';
24	  if (model.includes('sonnet')) return 'sonnet';
25	  return '';
26	}
