121	/**
122	 * Render a single content block.
123	 */
124	function renderContentBlock(block) {
125	  if (block.type === 'text') {
126	    return renderTextContent(block.text || '');
127	  }
128	
129	  if (block.type === 'tool_use') {
130	    const div = document.createElement('div');
131	    div.className = 'tool-use-block';
132	
133	    const header = document.createElement('div');
134	    header.className = 'tool-use-header';
135	    header.textContent = `Tool Call: ${block.name || 'unknown'}`;
136	    div.appendChild(header);
137	
138	    if (block.input) {
139	      const details = document.createElement('details');
140	      details.className = 'collapsible';
141	      const summary = document.createElement('summary');
142	      summary.textContent = 'Input';
143	      const badge = document.createElement('span');
144	      badge.className = 'collapsible-badge';
145	      badge.textContent = typeof block.input === 'string'
146	        ? `${block.input.length} chars`
147	        : `${Object.keys(block.input).length} keys`;
148	      summary.appendChild(badge);
149	      details.appendChild(summary);
150	
151	      const content = document.createElement('div');
152	      content.className = 'collapsible-content';
153	      content.appendChild(createJsonView(block.input));
154	      details.appendChild(content);
155	      div.appendChild(details);
156	    }
157	
158	    return div;
159	  }
160	
161	  if (block.type === 'tool_result') {
162	    const div = document.createElement('div');
163	    div.className = 'tool-result-block';
164	
165	    const header = document.createElement('div');
166	    header.className = 'tool-result-header';
167	    header.textContent = `Tool Result${block.tool_use_id ? ` (${block.tool_use_id.substring(0, 8)}...)` : ''}`;
168	    div.appendChild(header);
169	
170	    if (block.content) {
171	      const contentBlocks = normalizeContent(block.content);
172	      for (const cb of contentBlocks) {
173	        div.appendChild(renderContentBlock(cb));
174	      }
175	    }
176	
177	    return div;
178	  }
179	
180	  // Fallback: show raw JSON
181	  const div = document.createElement('div');
182	  div.className = 'content-block';
183	  div.appendChild(createJsonView(block));
184	  return div;
185	}
