252	/**
253	 * Render the Messages tab content.
254	 */
255	export function renderMessagesTab(entry) {
256	  const container = document.createElement('div');
257	  const messages = entry.anthropicRequest?.messages || [];
258	
259	  if (messages.length === 0) {
260	    container.textContent = 'No messages in this entry.';
261	    return container;
262	  }
263	
264	  for (const msg of messages) {
265	    const msgDiv = document.createElement('div');
266	    msgDiv.className = `message ${msg.role}`;
267	
268	    const header = document.createElement('div');
269	    header.className = 'message-header';
270	    header.innerHTML = `<span>${escapeHtml(msg.role.toUpperCase())}</span>`;
271	
272	    const body = document.createElement('div');
273	    body.className = 'message-body';
274	
275	    const blocks = normalizeContent(msg.content);
276	    for (const block of blocks) {
277	      const rendered = renderContentBlock(block);
278	      body.appendChild(rendered);
279	    }
280	
281	    msgDiv.appendChild(header);
282	    msgDiv.appendChild(body);
283	    container.appendChild(msgDiv);
284	  }
285	
286	  return container;
287	}
