418	    summary.messages = (summary.messages || []).map((m, i) => ({
419	      role: m.role,
420	      content: `[${(m.content || '').length} chars]`,
421	      _index: i,
422	    }));
423	    summary.tools = `[${(summary.tools || []).length} tools]`;
424	    openaiCol.appendChild(createJsonView(summary));
