1	/**
2	 * Parser module for Copilot Adapter log files.
3	 * Handles JSON parsing (including truncated files) and SSE response parsing.
4	 */
5	
6	/**
7	 * Parse a log file text into an array of log entries.
8	 * Handles truncated JSON arrays (missing trailing `]`).
9	 * @param {string} text - Raw file content
10	 * @returns {{ entries: object[], truncated: boolean }}
11	 */
12	export function parseLogFile(text) {
13	  const trimmed = text.trim();
14	  let truncated = false;
15	
16	  // Try parsing as-is first
17	  try {
18	    const data = JSON.parse(trimmed);
19	    if (Array.isArray(data)) {
20	      return { entries: data, truncated: false };
21	    }
22	    // Single object, wrap in array
23	    return { entries: [data], truncated: false };
24	  } catch {
25	    // Likely truncated, try to fix
26	  }
27	
28	  // Try appending `]` to close the array
29	  try {
30	    const fixed = trimmed + '\n]';
31	    const data = JSON.parse(fixed);
32	    if (Array.isArray(data)) {
33	      return { entries: data, truncated: true };
34	    }
35	  } catch {
36	    // Try appending `}]` in case a trailing object is incomplete
37	  }
38	
39	  // Try appending `}]`
40	  try {
41	    const fixed = trimmed + '\n}]';
42	    const data = JSON.parse(fixed);
43	    if (Array.isArray(data)) {
44	      return { entries: data, truncated: true };
45	    }
46	  } catch {
47	    // Final fallback: try JSONL (one JSON object per line)
48	  }
49	
50	  // Fallback: try parsing as JSONL
51	  const entries = [];
52	  for (const line of trimmed.split('\n')) {
53	    const l = line.trim();
54	    if (!l || l === '[' || l === ']') continue;
55	    // Strip trailing comma
56	    const cleaned = l.endsWith(',') ? l.slice(0, -1) : l;
57	    try {
58	      entries.push(JSON.parse(cleaned));
59	    } catch {
60	      // skip unparseable lines
61	    }
62	  }
63	
64	  if (entries.length > 0) {
65	    return { entries, truncated: true };
66	  }
67	
68	  throw new Error('Unable to parse log file. Expected a JSON array of log entries.');
69	}
70	
71	/**
72	 * Parse SSE response text into assembled content and usage stats.
73	 * @param {string} sseText - Raw SSE response text
74	 * @returns {{ content: string, usage: object|null, model: string|null, chunks: object[] }}
75	 */
76	export function parseSSEResponse(sseText) {
77	  if (!sseText) return { content: '', usage: null, model: null, chunks: [] };
78	
79	  const lines = sseText.split('\n');
80	  const chunks = [];
81	  let content = '';
82	  let usage = null;
83	  let model = null;
84	
85	  for (const line of lines) {
86	    const trimmed = line.trim();
87	    if (!trimmed.startsWith('data:')) continue;
88	
89	    const dataStr = trimmed.slice(5).trim();
90	    if (dataStr === '[DONE]') continue;
91	
92	    try {
93	      const data = JSON.parse(dataStr);
94	      chunks.push(data);
95	
96	      if (data.model && !model) {
97	        model = data.model;
98	      }
99	
100	      // Extract content from OpenAI-format streaming
101	      if (data.choices) {
102	        for (const choice of data.choices) {
103	          if (choice.delta?.content) {
104	            content += choice.delta.content;
105	          }
106	        }
107	      }
108	
109	      // Extract usage stats
110	      if (data.usage) {
111	        usage = data.usage;
112	      }
113	    } catch {
114	      // Skip unparseable SSE chunks
115	    }
116	  }
117	
118	  return { content, usage, model, chunks };
119	}
120	
121	/**
122	 * Normalize message content to an array of content blocks.
123	 * @param {string|object[]} content
124	 * @returns {object[]}
125	 */
126	export function normalizeContent(content) {
127	  if (!content) return [];
128	  if (typeof content === 'string') {
129	    return [{ type: 'text', text: content }];
130	  }
131	  if (Array.isArray(content)) {
132	    return content;
133	  }
134	  return [content];
135	}
136	
137	/**
138	 * Extract summary metadata from a log entry.
139	 * @param {object} entry
140	 * @param {number} index
141	 * @returns {object}
142	 */
143	export function extractMetadata(entry, index) {
144	  const req = entry.anthropicRequest || {};
145	  const parsedResponse = parseSSEResponse(entry.copilotResponse);
146	
147	  return {
148	    index,
149	    timestamp: entry.timestamp || null,
150	    model: req.model || 'unknown',
151	    streaming: entry.streaming ?? null,
152	    messageCount: req.messages?.length || 0,
153	    systemPromptCount: req.system?.length || 0,
154	    toolCount: req.tools?.length || 0,
155	    maxTokens: req.max_tokens || null,
156	    temperature: req.temperature ?? null,
157	    usage: parsedResponse.usage,
158	    responseModel: parsedResponse.model,
159	    responseContentLength: parsedResponse.content.length,
160	  };
161	}
162	
163	/**
164	 * Format a timestamp for display.
165	 * @param {string} isoString
166	 * @returns {string}
167	 */
168	export function formatTimestamp(isoString) {
169	  if (!isoString) return 'N/A';
170	  try {
171	    const d = new Date(isoString);
172	    return d.toLocaleString(undefined, {
173	      month: 'short',
174	      day: 'numeric',
175	      hour: '2-digit',
176	      minute: '2-digit',
177	      second: '2-digit',
178	    });
179	  } catch {
180	    return isoString;
181	  }
182	}
183	
184	/**
185	 * Format byte size for display.
186	 * @param {number} bytes
187	 * @returns {string}
188	 */
189	export function formatSize(bytes) {
190	  if (bytes < 1024) return bytes + ' B';
191	  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
192	  return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
193	}
