1	/**
2	 * Parser module for Copilot Adapter log files.
3	 * Handles JSON parsing (including truncated files) and SSE response parsing.
4	 */
5	
6	/**
7	 * Parse a log file text into an array of log entries.
8	 * Handles truncated JSON arrays (missing trailing `]`).
9	 * @param {string} text - Raw file content
10	 * @returns {{ entries: object[], truncated: boolean }}
11	 */
12	export function parseLogFile(text) {
13	  const trimmed = text.trim();
14	  let truncated = false;
15	
16	  // Try parsing as-is first
17	  try {
18	    const data = JSON.parse(trimmed);
19	    if (Array.isArray(data)) {
20	      return { entries: data, truncated: false };
21	    }
22	    // Single object, wrap in array
23	    return { entries: [data], truncated: false };
24	  } catch {
25	    // Likely truncated, try to fix
26	  }
27	
28	  // Try appending `]` to close the array
29	  try {
30	    const fixed = trimmed + '\n]';
31	    const data = JSON.parse(fixed);
32	    if (Array.isArray(data)) {
33	      return { entries: data, truncated: true };
34	    }
35	  } catch {
36	    // Try appending `}]` in case a trailing object is incomplete
37	  }
38	
39	  // Try appending `}]`
40	  try {
41	    const fixed = trimmed + '\n}]';
42	    const data = JSON.parse(fixed);
43	    if (Array.isArray(data)) {
44	      return { entries: data, truncated: true };
45	    }
46	  } catch {
47	    // Final fallback: try JSONL (one JSON object per line)
48	  }
49	
50	  // Fallback: try parsing as JSONL
51	  const entries = [];
52	  for (const line of trimmed.split('\n')) {
53	    const l = line.trim();
54	    if (!l || l === '[' || l === ']') continue;
55	    // Strip trailing comma
56	    const cleaned = l.endsWith(',') ? l.slice(0, -1) : l;
57	    try {
58	      entries.push(JSON.parse(cleaned));
59	    } catch {
60	      // skip unparseable lines
61	    }
62	  }
63	
64	  if (entries.length > 0) {
65	    return { entries, truncated: true };
66	  }
67	
68	  throw new Error('Unable to parse log file. Expected a JSON array of log entries.');
69	}
