71	/**
72	 * Parse SSE response text into assembled content and usage stats.
73	 * @param {string} sseText - Raw SSE response text
74	 * @returns {{ content: string, usage: object|null, model: string|null, chunks: object[] }}
75	 */
76	export function parseSSEResponse(sseText) {
77	  if (!sseText) return { content: '', usage: null, model: null, chunks: [] };
78	
79	  const lines = sseText.split('\n');
80	  const chunks = [];
81	  let content = '';
82	  let usage = null;
83	  let model = null;
84	
85	  for (const line of lines) {
86	    const trimmed = line.trim();
87	    if (!trimmed.startsWith('data:')) continue;
88	
89	    const dataStr = trimmed.slice(5).trim();
90	    if (dataStr === '[DONE]') continue;
91	
92	    try {
93	      const data = JSON.parse(dataStr);
94	      chunks.push(data);
95	
96	      if (data.model && !model) {
97	        model = data.model;
98	      }
99	
100	      // Extract content from OpenAI-format streaming
101	      if (data.choices) {
102	        for (const choice of data.choices) {
103	          if (choice.delta?.content) {
104	            content += choice.delta.content;
105	          }
106	        }
107	      }
108	
109	      // Extract usage stats
110	      if (data.usage) {
111	        usage = data.usage;
112	      }
113	    } catch {
114	      // Skip unparseable SSE chunks
115	    }
116	  }
117	
118	  return { content, usage, model, chunks };
119	}
