137	/**
138	 * Extract summary metadata from a log entry.
139	 * @param {object} entry
140	 * @param {number} index
141	 * @returns {object}
142	 */
143	export function extractMetadata(entry, index) {
144	  const req = entry.anthropicRequest || {};
145	  const parsedResponse = parseSSEResponse(entry.copilotResponse);
146	
147	  return {
148	    index,
149	    timestamp: entry.timestamp || null,
150	    model: req.model || 'unknown',
151	    streaming: entry.streaming ?? null,
152	    messageCount: req.messages?.length || 0,
153	    systemPromptCount: req.system?.length || 0,
154	    toolCount: req.tools?.length || 0,
155	    maxTokens: req.max_tokens || null,
156	    temperature: req.temperature ?? null,
157	    usage: parsedResponse.usage,
158	    responseModel: parsedResponse.model,
159	    responseContentLength: parsedResponse.content.length,
160	  };
161	}
