163	/**
164	 * Format a timestamp for display.
165	 * @param {string} isoString
166	 * @returns {string}
167	 */
168	export function formatTimestamp(isoString) {
169	  if (!isoString) return 'N/A';
170	  try {
171	    const d = new Date(isoString);
172	    return d.toLocaleString(undefined, {
173	      month: 'short',
174	      day: 'numeric',
175	      hour: '2-digit',
176	      minute: '2-digit',
177	      second: '2-digit',
178	    });
179	  } catch {
180	    return isoString;
181	  }
182	}
183	
184	/**
185	 * Format byte size for display.
186	 * @param {number} bytes
187	 * @returns {string}
188	 */
189	export function formatSize(bytes) {
190	  if (bytes < 1024) return bytes + ' B';
191	  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
192	  return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
193	}
