60	  const pre = document.createElement('div');
61	  pre.className = 'json-view';
62	  const text = typeof obj === 'string' ? obj : JSON.stringify(obj, null, 2);
63	  pre.textContent = text;
64	
65	  container.appendChild(pre);
66	  container.appendChild(createCopyButton(text));
67	  return container;
