75	// ===== File Loading =====
76	function handleFiles(files) {
77	  if (!files || files.length === 0) return;
78	
79	  const file = files[0]; // Handle first file
80	  const reader = new FileReader();
81	
82	  reader.onload = (e) => {
83	    try {
84	      const result = parseLogFile(e.target.result);
85	      loadEntries(result.entries, file.name, file.size, result.truncated);
86	    } catch (err) {
87	      alert(`Error parsing file: ${err.message}`);
88	    }
89	  };
90	
91	  reader.onerror = () => {
92	    alert('Error reading file.');
93	  };
94	
95	  reader.readAsText(file);
96	}
