31	function createCopyButton(text) {
32	  const btn = document.createElement('button');
33	  btn.className = 'copy-btn';
34	  btn.textContent = 'Copy';
35	  btn.addEventListener('click', async (e) => {
36	    e.stopPropagation();
37	    try {
38	      await navigator.clipboard.writeText(text);
39	      btn.textContent = 'Copied!';
40	      btn.classList.add('copied');
41	      setTimeout(() => {
42	        btn.textContent = 'Copy';
43	        btn.classList.remove('copied');
44	      }, 1500);
45	    } catch {
46	      btn.textContent = 'Failed';
47	      setTimeout(() => { btn.textContent = 'Copy'; }, 1500);
48	    }
49	  });
50	  return btn;
51	}
