121	/**
122	 * Normalize message content to an array of content blocks.
123	 * @param {string|object[]} content
124	 * @returns {object[]}
125	 */
126	export function normalizeContent(content) {
127	  if (!content) return [];
128	  if (typeof content === 'string') {
129	    return [{ type: 'text', text: content }];
130	  }
131	  if (Array.isArray(content)) {
132	    return content;
133	  }
134	  return [content];
135	}
