315	// ===== Event Listeners =====
316	function initEventListeners() {
317	  // Theme toggle
318	  themeToggle.addEventListener('click', toggleTheme);
319	
320	  // Close file
321	  closeFileBtn.addEventListener('click', closeFile);
322	
323	  // Tab switching
324	  tabs.addEventListener('click', (e) => {
325	    const tab = e.target.closest('.tab');
326	    if (tab && tab.dataset.tab) {
327	      setActiveTab(tab.dataset.tab);
328	    }
329	  });
330	
331	  // Model filter
332	  modelFilter.addEventListener('change', applyFilters);
333	
334	  // Search with debounce
335	  let searchTimeout;
336	  searchInput.addEventListener('input', () => {
337	    clearTimeout(searchTimeout);
338	    searchTimeout = setTimeout(applyFilters, 300);
339	  });
340	
341	  // Keyboard navigation (works with filtered list)
342	  document.addEventListener('keydown', (e) => {
343	    if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT') return;
344	    if (state.filteredEntries.length === 0) return;
345	
346	    // Find current position in filtered list
347	    const currentEntry = state.entries[state.selectedIndex];
348	    const filteredIdx = state.filteredEntries.indexOf(currentEntry);
349	
350	    if (e.key === 'ArrowUp') {
351	      const prevIdx = filteredIdx > 0 ? filteredIdx - 1 : 0;
352	      const originalIndex = state.entries.indexOf(state.filteredEntries[prevIdx]);
353	      if (originalIndex >= 0) selectEntry(originalIndex);
354	    } else if (e.key === 'ArrowDown') {
355	      const nextIdx = filteredIdx < state.filteredEntries.length - 1 ? filteredIdx + 1 : filteredIdx;
356	      const originalIndex = state.entries.indexOf(state.filteredEntries[nextIdx]);
357	      if (originalIndex >= 0) selectEntry(originalIndex);
358	    }
359	  });
360	}
361	
362	// ===== Initialize =====
363	function init() {
364	  initTheme();
365	  initDragDrop();
366	  initEventListeners();
367	}
368	
369	document.addEventListener('DOMContentLoaded', init);
