70	/**
71	 * Escape HTML characters.
72	 */
73	function escapeHtml(str) {
74	  const div = document.createElement('div');
75	  div.textContent = str;
76	  return div.innerHTML;
77	}
78	
79	/**
80	 * Render text content with basic markdown code block handling.
81	 */
82	function renderTextContent(text) {
83	  const div = document.createElement('div');
84	  div.className = 'text-content';
85	
86	  // Split on code blocks (```...```)
87	  const parts = text.split(/(```[\s\S]*?```)/g);
88	
89	  for (const part of parts) {
90	    if (part.startsWith('```')) {
91	      const codeBlock = document.createElement('div');
92	      codeBlock.className = 'code-block';
93	
94	      const content = part.slice(3, -3);
95	      const firstNewline = content.indexOf('\n');
96	      const lang = firstNewline > 0 ? content.slice(0, firstNewline).trim() : '';
97	      const code = firstNewline > 0 ? content.slice(firstNewline + 1) : content;
98	
99	      const pre = document.createElement('pre');
100	      const codeEl = document.createElement('code');
101	      codeEl.textContent = code;
102	      if (lang) codeEl.dataset.lang = lang;
103	      pre.appendChild(codeEl);
104	      codeBlock.appendChild(pre);
105	      codeBlock.appendChild(createCopyButton(code));
106	      div.appendChild(codeBlock);
107	    } else if (part.trim()) {
108	      // Handle inline code
109	      const span = document.createElement('span');
110	      span.innerHTML = escapeHtml(part).replace(
111	        /`([^`]+)`/g,
112	        '<code class="inline-code">$1</code>'
113	      );
114	      div.appendChild(span);
115	    }
116	  }
117	
118	  return div;
119	}
