441	  // Assembled content
442	  const contentSection = document.createElement('div');
443	  contentSection.className = 'response-content';
444	  const contentTitle = document.createElement('h3');
445	  contentTitle.textContent = 'Assembled Response';
446	  contentTitle.style.marginBottom = '8px';
447	  contentTitle.style.fontSize = '14px';
448	  contentSection.appendChild(contentTitle);
449	
450	  if (parsed.content) {
451	    contentSection.appendChild(renderTextContent(parsed.content));
452	  } else {
453	    const empty = document.createElement('div');
454	    empty.style.color = 'var(--text-muted)';
455	    empty.textContent = 'No content extracted from response.';
456	    contentSection.appendChild(empty);
457	  }
458	  container.appendChild(contentSection);
459	
460	  // Usage stats
461	  if (parsed.usage) {
462	    const usageTitle = document.createElement('h3');
463	    usageTitle.textContent = 'Usage Statistics';
464	    usageTitle.style.marginBottom = '8px';
465	    usageTitle.style.fontSize = '14px';
466	    container.appendChild(usageTitle);
467	
468	    const statsGrid = document.createElement('div');
469	    statsGrid.className = 'usage-stats';
470	
471	    const usageItems = [
472	      { label: 'Prompt Tokens', value: parsed.usage.prompt_tokens },
473	      { label: 'Completion Tokens', value: parsed.usage.completion_tokens },
474	      { label: 'Total Tokens', value: parsed.usage.total_tokens },
475	    ];
476	
477	    if (parsed.usage.prompt_tokens_details?.cached_tokens != null) {
478	      usageItems.push({
479	        label: 'Cached Tokens',
480	        value: parsed.usage.prompt_tokens_details.cached_tokens,
481	      });
482	    }
483	
484	    for (const { label, value } of usageItems) {
485	      if (value == null) continue;
486	      const stat = document.createElement('div');
487	      stat.className = 'usage-stat';
488	      stat.innerHTML = `<div class="label">${escapeHtml(label)}</div><div class="value">${Number(value).toLocaleString()}</div>`;
489	      statsGrid.appendChild(stat);
490	    }
491	    container.appendChild(statsGrid);
492	  }
493	
494	  // Response model
495	  if (parsed.model) {
496	    const modelInfo = document.createElement('div');
497	    modelInfo.style.marginTop = '12px';
498	    modelInfo.style.fontSize = '13px';
499	    modelInfo.style.color = 'var(--text-secondary)';
500	    modelInfo.textContent = `Response Model: ${parsed.model}`;
501	    container.appendChild(modelInfo);
502	  }
503	
504	  // Raw SSE (collapsible)
505	  if (entry.copilotResponse) {
506	    const rawDetails = document.createElement('details');
507	    rawDetails.className = 'collapsible';
508	    rawDetails.style.marginTop = '16px';
509	    const rawSummary = document.createElement('summary');
510	    rawSummary.textContent = 'Raw SSE Response';
511	    const badge = document.createElement('span');
512	    badge.className = 'collapsible-badge';
513	    badge.textContent = `${entry.copilotResponse.length} chars`;
514	    rawSummary.appendChild(badge);
515	    rawDetails.appendChild(rawSummary);
516	
517	    const rawContent = document.createElement('div');
518	    rawContent.className = 'collapsible-content';
519	    rawContent.appendChild(createJsonView(entry.copilotResponse));
520	    rawDetails.appendChild(rawContent);
521	    container.appendChild(rawDetails);
522	  }
523	
524	  return container;
525	}
